/**
 * @name startsWith path check using getAbsolutePath instead of getCanonicalPath
 * @description Path containment checks using startsWith() with getAbsolutePath() are bypassable via path traversal sequences
 * @kind path-problem
 * @problem.severity error
 * @id java/startswith-absolutepath-bypass
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module StartsWithAbsPathConfig implements DataFlow::ConfigSig {
  // Source: getAbsolutePath() used without getCanonicalPath()
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getAbsolutePath") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.io", "File") and
      source.asExpr() = mc
    )
  }

  // Sink: startsWith() call (containment check)
  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("startsWith") and
      (
        sink.asExpr() = mc.getQualifier() or
        sink.asExpr() = mc.getArgument(0)
      )
    )
  }
}

module StartsWithAbsPathFlow = TaintTracking::Global<StartsWithAbsPathConfig>;
import StartsWithAbsPathFlow::PathGraph

from StartsWithAbsPathFlow::PathNode source, StartsWithAbsPathFlow::PathNode sink
where StartsWithAbsPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path containment check uses getAbsolutePath() $@ with startsWith() - bypassable without getCanonicalPath() canonicalization.", source.getNode(), "getAbsolutePath()"

/**
 * @name Archive resource name flows to FileOutputStream or FileInputStream
 * @description Archive entry names that flow to FileOutputStream/FileInputStream without validation
 * @kind path-problem
 * @problem.severity error
 * @id java/archive-entry-to-filestream
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module EntryToStreamConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("getName") or mc.getMethod().hasName("getSymlinkDestination") or mc.getMethod().hasName("getLinkName")) and
      (
        mc.getMethod().getDeclaringType().getName().matches("%Entry%") or
        mc.getMethod().getDeclaringType().getName().matches("%Resource%")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      (
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileWriter") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "RandomAccessFile")
      ) and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module EntryToStreamFlow = TaintTracking::Global<EntryToStreamConfig>;
import EntryToStreamFlow::PathGraph

from EntryToStreamFlow::PathNode source, EntryToStreamFlow::PathNode sink
where EntryToStreamFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Archive entry name $@ flows to file stream constructor without path traversal validation.", source.getNode(), "entry name"
